## Proof of Concept: mcp-bridge Plugin

I have implemented a working MCP bridge plugin. Here is the complete code for reference:

### File 1: `~/.openclaw/extensions/mcp-bridge/package.json`

```json
{
  "name": "@openclaw/mcp-bridge",
  "version": "1.0.0",
  "type": "module",
  "description": "Bridge MCP servers (via mcporter) to OpenClaw tools",
  "license": "MIT",
  "openclaw": {
    "extensions": ["./src/index.js"]
  },
  "main": "src/index.js",
  "peerDependencies": {
    "openclaw": ">=2026.1.29"
  }
}
```

### File 2: `~/.openclaw/extensions/mcp-bridge/openclaw.plugin.json`

```json
{
  "id": "mcp-bridge",
  "version": "1.0.0",
  "kind": "tool-provider",
  "description": "Bridge MCP servers to OpenClaw tools via mcporter CLI",
  "configSchema": {
    "type": "object",
    "properties": {
      "enabled": {
        "type": "boolean",
        "default": true,
        "description": "Enable or disable MCP bridge"
      },
      "servers": {
        "type": "array",
        "items": { "type": "string" },
        "default": [],
        "description": "List of MCP server names to bridge (empty = all)"
      },
      "toolPrefix": {
        "type": "string",
        "default": "mcp_",
        "description": "Prefix for generated tool names"
      }
    }
  }
}
```

### File 3: `~/.openclaw/extensions/mcp-bridge/src/index.js`

See next comment for the main implementation...

---

**Usage:**

1. Create the directory structure:
```bash
mkdir -p ~/.openclaw/extensions/mcp-bridge/src
```

2. Create the three files above

3. Enable in `~/.openclaw/openclaw.json`:
```json
{
  "plugins": {
    "entries": {
      "mcp-bridge": { "enabled": true }
    }
  }
}
```

4. Restart Gateway:
```bash
openclaw gateway restart
```

5. Verify in logs:
```
[plugins] mcp-bridge: registered 14 MCP tools from 3 servers
```

## Proof of Concept: mcp-bridge Plugin (Source Code)

### File 3: `~/.openclaw/extensions/mcp-bridge/src/index.js`

```javascript
/**
 * MCP Bridge Plugin - Bridges MCP servers (via mcporter) to OpenClaw tools
 *
 * This plugin:
 * 1. Calls `mcporter list --json` at startup to discover all available tools
 * 2. Creates an OpenClaw tool for each MCP tool
 * 3. When executed, calls `mcporter call <server>.<tool>` to run the tool
 */

import { exec } from "child_process";

const DEFAULT_CONFIG = {
	enabled: true,
	servers: [], // empty = all servers
	toolPrefix: "mcp_",
};

/**
 * Execute mcporter CLI and return JSON result
 */
async function mcporterExec(args, logger) {
	return new Promise((resolve, reject) => {
		const cmd = `mcporter ${args.join(" ")}`;
		logger.debug(`mcp-bridge: executing: ${cmd}`);

		exec(cmd, { maxBuffer: 10 * 1024 * 1024 }, (error, stdout, stderr) => {
			if (error) {
				logger.error(`mcp-bridge: mcporter failed: ${error.message}`);
				reject(new Error(`mcporter error: ${error.message}`));
				return;
			}
			if (stderr && !stdout) {
				reject(new Error(`mcporter stderr: ${stderr}`));
				return;
			}
			try {
				const result = JSON.parse(stdout);
				resolve(result);
			} catch (e) {
				// Not JSON, return raw output
				resolve({ raw: stdout });
			}
		});
	});
}

/**
 * Create an OpenClaw tool from an MCP tool definition
 */
function createMcpTool(serverName, tool, config, logger) {
	const toolName = `${config.toolPrefix}${serverName}_${tool.name}`;

	// Build parameter schema from MCP tool's inputSchema or create a generic one
	const parameters = tool.inputSchema || {
		type: "object",
		properties: {},
		additionalProperties: true,
	};

	return {
		name: toolName,
		description: `[MCP/${serverName}] ${tool.description || "No description available"}`,
		parameters,
		async execute(_toolCallId, params) {
			try {
				// Build mcporter call arguments
				const callArgs = ["call", "--json", `${serverName}.${tool.name}`];

				// Add parameters as key=value flags
				if (params && typeof params === "object") {
					for (const [key, value] of Object.entries(params)) {
						if (value === undefined || value === null) continue;

						if (typeof value === "object") {
							// JSON-encode complex values
							callArgs.push(`${key}=${JSON.stringify(value)}`);
						} else {
							callArgs.push(`${key}=${String(value)}`);
						}
					}
				}

				const result = await mcporterExec(callArgs, logger);

				// Format the response
				if (result.content) {
					// MCP-style response with content blocks
					const textBlocks = result.content
						.filter((block) => block.type === "text")
						.map((block) => block.text)
						.join("\n");

					return {
						content: [{ type: "text", text: textBlocks || JSON.stringify(result, null, 2) }],
					};
				}

				// Raw result
				return {
					content: [
						{
							type: "text",
							text: typeof result === "string" ? result : JSON.stringify(result, null, 2),
						},
					],
				};
			} catch (err) {
				const msg = err instanceof Error ? err.message : String(err);
				logger.error(`mcp-bridge: ${toolName} failed: ${msg}`);
				return {
					content: [{ type: "text", text: `Error: ${msg}` }],
				};
			}
		},
	};
}

export default {
	id: "mcp-bridge",
	name: "MCP Bridge",
	description: "Bridge MCP servers (via mcporter CLI) to OpenClaw tools",

	register(api) {
		const logger = api.logger;
		const rawConfig = api.pluginConfig || {};
		const config = { ...DEFAULT_CONFIG, ...rawConfig };

		if (!config.enabled) {
			logger.info("mcp-bridge: disabled by config");
			return;
		}

		logger.info("mcp-bridge: discovering MCP tools...");

		// Discover tools from mcporter
		mcporterExec(["list", "--json"], logger)
			.then((result) => {
				if (!result.servers || !Array.isArray(result.servers)) {
					logger.warn("mcp-bridge: no servers found in mcporter output");
					return;
				}

				let toolCount = 0;

				for (const server of result.servers) {
					// Skip servers not in allowlist (if configured)
					if (
						config.servers.length > 0 &&
						!config.servers.includes(server.name) &&
						!config.servers.includes("*")
					) {
						logger.debug(`mcp-bridge: skipping server ${server.name} (not in allowlist)`);
						continue;
					}

					// Skip offline/error servers
					if (server.status !== "ok") {
						logger.warn(
							`mcp-bridge: skipping server ${server.name} (status: ${server.status})`,
						);
						continue;
					}

					// Register tools from this server
					if (server.tools && Array.isArray(server.tools)) {
						for (const tool of server.tools) {
							try {
								const openclawTool = createMcpTool(
									server.name,
									tool,
									config,
									logger,
								);
								api.registerTool(openclawTool);
								toolCount++;
							} catch (err) {
								logger.error(
									`mcp-bridge: failed to create tool ${server.name}.${tool.name}: ${err.message}`,
								);
							}
						}
					}
				}

				logger.info(
					`mcp-bridge: registered ${toolCount} MCP tools from ${result.servers.length} servers`,
				);
			})
			.catch((err) => {
				logger.error(`mcp-bridge: failed to discover tools: ${err.message}`);
			});
	},
};
```

---

**Usage:**

1. Create the directory structure:
```bash
mkdir -p ~/.openclaw/extensions/mcp-bridge/src
```

2. Create the three files above in their respective locations.

3. Enable in `~/.openclaw/openclaw.json`:
```json
{
  "plugins": {
    "entries": {
      "mcp-bridge": { "enabled": true }
    }
  }
}
```

4. Restart Gateway:
```bash
openclaw gateway restart
```

5. Verify in logs:
```
mcp-bridge: registered 14 MCP tools from 3 servers
```

## 🔧 Hephaestus Code Review Analysis

### Root Cause Identified

The stale-socket detection logic in `channel-health-monitor.ts` has an edge case that causes false positives in multi-account/low-traffic scenarios.

**The problematic code:**
```typescript
// Line 62-72 in isChannelHealthy()
if (snapshot.lastEventAt != null || snapshot.lastStartAt != null) {
  const upSince = snapshot.lastStartAt ?? 0;
  const upDuration = opts.now - upSince;
  if (upDuration > opts.staleEventThresholdMs) {
    const lastEvent = snapshot.lastEventAt ?? 0;  // <-- BUG: treats null as epoch
    const eventAge = opts.now - lastEvent;
    if (eventAge > opts.staleEventThresholdMs) {
      return false;  // <-- Marks as unhealthy
    }
  }
}
```

**The issue:**
- If `lastEventAt` is `null` (channel never received an event), then `lastEvent = 0`
- `eventAge = now - 0` = current timestamp (definitely > 30 min threshold)
- Any channel running >30 min with no events gets marked as `stale-socket`

**Why this happens in multi-account setups:**
1. All 9 channels start around the same time
2. Low-traffic channels (Telegram bots, Slack with quiet servers) may not receive events for hours
3. After 30 min of no events, health monitor restarts them
4. Restart creates new socket, but if still no traffic → cycle repeats

**Existing test confirms this is intentional behavior:**
```typescript
// channel-health-monitor.test.ts:235
it("restarts a channel that never received any event past the stale threshold", async () => {
  // ... expects restart when lastEventAt is undefined
});
```

### Suggested Fixes

**Option A: Require prior event before stale detection**
Only treat as stale if we've seen at least one event:
```typescript
if (upDuration > opts.staleEventThresholdMs) {
  // Only consider stale if we've seen events before
  if (snapshot.lastEventAt == null) {
    return true;  // Never received event = can't determine staleness
  }
  const eventAge = opts.now - snapshot.lastEventAt;
  if (eventAge > opts.staleEventThresholdMs) {
    return false;
  }
}
```

**Option B: Channel-type-specific thresholds**
Telegram polling has different traffic patterns than Slack WebSocket.

**Option C: Configurable disable**
Add `disableStaleDetection: true` option per channel or globally.

**Option D: Use lastSuccessfulPoll/heartbeat**
Instead of just `lastEventAt`, track successful connection health.

### Workaround (Immediate)

Set a very high stale threshold in gateway config:
```yaml
healthCheck:
  staleEventThresholdMs: 86400000  # 24 hours
\}```

Or disable health check entirely (not recommended):
```yaml
healthCheck:
  disabled: true
```

---

Would be happy to submit a PR for Option A if the maintainers agree with the approach. The test at line 235 would need to be updated to reflect the new expected behavior.
